 * Checks if a number is prime.
 * A prime number is a natural number greater than 1 that has no positive divisors other than 1 and itself.
 * @param {number} n
 * @returns {boolean}
 */
function isPrime(n) {
    if (n <= 1) return false;
    if (n <= 3) return true;
    if (n % 2 === 0 || n % 3 === 0) return false;
    for (let i = 5; i * i <= n; i = i + 6) {
        if (n % i === 0 || n % (i + 2) === 0) return false;
    }
    return true;
}

/**
 * Finds the smallest number >= n that is prime.
 * @param {number} n
 * @returns {number}
 */
function findNextPrime(n) {
    let num = Math.max(2, n);
    while (true) {
        if (isPrime(num)) {
            return num;
        }
        num++;
    }
}

/**
 * Finds the smallest number >= n that is not prime (i.e., composite or 1).
 * Since nums[i] >= 1, we look for the smallest non-prime >= n.
 * 1 is not prime. 4, 6, 8, 9, 10... are non-prime.
 * @param {number} n
 * @returns {number}
 */
function findNextNonPrime(n) {
    let num = Math.max(1, n);
    while (true) {
        if (!isPrime(num)) {
            return num;
        }
        num++;
    }
}

function solve(nums) {
    let totalOperations = 0;
    const n = nums.length;

    for (let i = 0; i < n; i++) {
        const currentVal = nums[i];

        if (i % 2 === 0) {
            // Even index: must be prime
            if (!isPrime(currentVal)) {
                // Find the smallest prime >= currentVal
                const nextPrime = findNextPrime(currentVal);
                const operations = nextPrime - currentVal;
                totalOperations += operations;
            }
            // If it's already prime, 0 operations needed.
        } else {
            // Odd index: must be non-prime
            if (isPrime(currentVal)) {
                // Find the smallest non-prime >= currentVal
                const nextNonPrime = findNextNonPrime(currentVal);
                const operations = nextNonPrime - currentVal;
                totalOperations += operations;
            }
            // If it's already non-prime, 0 operations needed.
        }
    }

    return totalOperations;
