    // Global cache for prime checks up to a reasonable limit (10^5 + small buffer)
    // Since the max input is 10^5, and we might need to go slightly higher, 
    // we can precompute primes using a sieve up to around 100005 + margin.
    static const int MAX_VAL = 100000 + 500; // Max input + buffer for finding next prime
    static bool is_prime_cache[MAX_VAL];

    void sieve() {
        std::fill(is_prime_cache, is_prime_cache + MAX_VAL, true);
        is_prime_cache[0] = is_prime_cache[1] = false;
        for (int p = 2; p * p < MAX_VAL; p++) {
            if (is_prime_cache[p]) {
                for (int i = p * p; i < MAX_VAL; i += p)
                    is_prime_cache[i] = false;
            }
        }
    }

    bool isPrime(long long n) {
        if (n < MAX_VAL) {
            return is_prime_cache[n];
        }
        // Fallback for numbers larger than the sieve limit, though input constraints suggest this shouldn't be necessary for the smallest targets.
        if (n <= 1) return false;
        if (n <= 3) return true;
        if (n % 2 == 0 || n % 3 == 0) return false;
        for (long long i = 5; i * i <= n; i = i + 6) {
            if (n % i == 0 || n % (i + 2) == 0) return false;
        }
        return true;
    }

    // Finds the smallest number >= n that is prime.
    long long findNextPrime(long long n) {
        long long num = std::max(2LL, n);
        // Since we expect the gap to be small, this loop is fast.
        while (true) {
            if (isPrime(num)) {
                return num;
            }
            num++;
        }
    }

    // Finds the smallest number >= n that is not prime (i.e., composite or 1).
    long long findNextNonPrime(long long n) {
        long long num = std::max(1LL, n);
        while (true) {
            if (!isPrime(num)) {
                return num;
            }
            num++;
        }
    }

public:
    // Static initialization block to run sieve once
    static bool sieve_initialized;

    void ensureSieve() {
        if (!sieve_initialized) {
            sieve();
            sieve_initialized = true;
        }
    }
};

